#include <stdio.h>
#include <stdlib.h>

// Function to check if a graph is bipartite
int isBipartite(int **graph, int *color, int node, int n) {
    if (color[node] == -1) {
        color[node] = 1;
        for (int i = 0; i < n; i++) {
            if (graph[node][i] && color[i] == -1) {
                if (!isBipartite(graph, color, i, n)) {
                    return 0;
                }
            } else if (graph[node][i] && color[i] == color[node]) {
                return 0;
            }
        }
    }
    return 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, q;
        scanf("%d %d", &n, &q);
        int **graph = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            graph[i] = (int *)malloc(n * sizeof(int));
            for (int j = 0; j < n; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < q; i++) {
            int u, v, val;
            scanf("%d %d %d", &u, &v, &val);
            u--;
            v--;
            if (val == 1) {
                graph[u][v] = 1;
                graph[v][u] = 1;
            }
        }
        int *color = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            color[i] = -1;
        }
        int possible = 1;
        for (int i = 0; i < n; i++) {
            if (color[i] == -1) {
                if (!isBipartite(graph, color, i, n)) {
                    possible = 0;
                    break;
                }
            }
        }
        if (possible) {
            printf("yes\n");
        } else {
            printf("no\n");
        }
        for (int i = 0; i < n; i++) {
            free(graph[i]);
        }
        free(graph);
        free(color);
    }
    return 0;
}

