import java.util.Scanner;
public class Main {
    // Function to check if a graph is bipartite
    public static boolean isBipartite(int[][] graph, int[] color, int node, int n) {
        if (color[node] == -1) {
            color[node] = 1;
            for (int i = 0; i < n; i++) {
                if (graph[node][i] == 1 && color[i] == -1) {
                    if (!isBipartite(graph, color, i, n)) {
                        return false;
                    }
                } else if (graph[node][i] == 1 && color[i] == color[node]) {
                    return false;
                }
            }
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int q = sc.nextInt();
            int[][] graph = new int[n][n];
            for (int i = 0; i < q; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                int val = sc.nextInt();
                if (val == 1) {
                    graph[u][v] = 1;
                    graph[v][u] = 1;
                }
            }
            int[] color = new int[n];
            for (int i = 0; i < n; i++) {
                color[i] = -1;
            }
            boolean possible = true;
            for (int i = 0; i < n; i++) {
                if (color[i] == -1) {
                    if (!isBipartite(graph, color, i, n)) {
                        possible = false;
                        break;
                    }
                }
            }
            if (possible) {
                System.out.println("yes");
            } else {
                System.out.println("no");
            }
        }
    }
}

